  const { strict: globalStrict } = globalOptions;

  afterEach(() => {
    act(() => {
      cleanup();
    });
  });

  return function configuredClientRender(element, options = {}) {
    const { strict = globalStrict, ...localOptions } = options;

    return clientRender(element, { ...localOptions, strict });
